const currentItem = $input.item.json;
const html = currentItem.data;

if (!html || typeof html !== 'string') {
  throw new Error('HTML data not found');
}

// Extraer API Key
const apiKeyMatch = html.match(/INNERTUBE_API_KEY[\s\S]*?\"([a-zA-Z0-9_-]+)\"/);
if (!apiKeyMatch || !apiKeyMatch[1]) {
  throw new Error('INNERTUBE_API_KEY not found in HTML');
}

// Extraer videoId del HTML
const htmlVideoIdMatch = html.match(/\"videoId\":\s*\"([a-zA-Z0-9_-]{11})\"/);
let videoId = htmlVideoIdMatch ? htmlVideoIdMatch[1] : null;

if (!videoId) {
  throw new Error('Could not extract videoId from HTML');
}

return {json: {
  apiKey: apiKeyMatch[1],
  videoId: videoId
}};

// Obtener los caption tracks del video
const captionTracks = $input.item.json?.captions?.playerCaptionsTracklistRenderer?.captionTracks || [];

if (!captionTracks || captionTracks.length === 0) {
  throw new Error('No caption tracks found for this video');
}

// Buscar el primer caption track con kind='asr' (autogenerado)
const asrTrack = captionTracks.find(track => track.kind === 'asr');

if (!asrTrack) {
  throw new Error('No auto-generated transcript (asr) found. Available tracks: ' + captionTracks.map(t => t.languageCode + ' (' + (t.kind || 'default') + ')').join(', '));
}

// Retornar baseUrl y metadata del track
return {json: {
  transcriptUrl: asrTrack.baseUrl,
  languageCode: asrTrack.languageCode,
  trackName: asrTrack.name?.simpleText || 'Auto-generated transcript',
  kind: asrTrack.kind
}};

// Función para decodificar entidades HTML
function decodeHTMLEntities(text) {
  const entityMap = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&#x27;': "'",
    '&apos;': "'",
    '&#x2F;': '/'
  };

  let decoded = text;
  for (const [entity, char] of Object.entries(entityMap)) {
    decoded = decoded.replace(new RegExp(entity, 'g'), char);
  }

  // Decodificar números hexadecimales (ej: &#39;, &#x1F;)
  decoded = decoded.replace(/&#x([a-fA-F0-9]+);/g, (match, hex) => {
    return String.fromCharCode(parseInt(hex, 16));
  });

  // Decodificar números decimales (ej: &#39;)
  decoded = decoded.replace(/&#(\d+);/g, (match, dec) => {
    return String.fromCharCode(parseInt(dec, 10));
  });

  return decoded;
}

const transcript = $input.item.json.transcript;
if (!transcript || !transcript.text || !Array.isArray(transcript.text)) {
  throw new Error('No transcript data found');
}

let fullTranscript = '';
transcript.text.forEach(item => {
  if (item._ && typeof item._ === 'string') {
    // Decodificar entidades HTML
    const decodedText = decodeHTMLEntities(item._);
    fullTranscript += decodedText + ' ';
  }
});

fullTranscript = fullTranscript.trim();
const wordCount = fullTranscript.split(/\s+/).filter(w => w.length > 0).length;

return {json: {
  transcript: transcript,
  fullTranscript: fullTranscript,
  wordCount: wordCount
}};
